BEGIN;

UPDATE friction_nodes SET name_en='Russia''s war in Ukraine', name_de='Russlands Krieg in der Ukraine', description_en='The Russia-Ukraine war (initiated 24 February 2022) and its surrounding contest of framings: battlefield operations, the campaign against energy and infrastructure on both sides, Western military and economic aid, peace negotiations, anti-corruption investigations of Ukrainian officials, and the sanctions regime on Russia. The scope of the war itself is contested vocabulary — Ukrainian/Western framing as full-scale invasion versus Russian framing as a limited special military operation. Coverage spans Ukrainian, Russian, Western mainstream, Eastern European, and Global South press with sharply divergent vocabularies for the same events.', description_de='Der russisch-ukrainische Krieg (begonnen am 24. Februar 2022) und sein umgebender Rahmungs-Wettstreit: Gefechtsoperationen, der beiderseitige Feldzug gegen Energie und Infrastruktur, westliche militaerische und wirtschaftliche Hilfe, Friedensverhandlungen, Anti-Korruptionsermittlungen gegen ukrainische Beamte und das Sanktionsregime gegen Russland. Der Umfang des Krieges selbst ist umkaempftes Vokabular — ukrainisch-westliche Rahmung als voll entfaltete Invasion gegenueber russischer Rahmung als begrenzte militaerische Spezialoperation. Berichterstattung umfasst ukrainische, russische, westliche, osteuropaeische und Global-South-Medien mit stark divergierenden Vokabularen fuer dieselben Ereignisse.', editorial_summary_en='Russia''s invasion of Ukraine, launched 24 February 2022, is the largest land war in Europe since 1945 and the organizing fact of the current European security order. Four axes of contest run through it: control of the front line itself, the scale and durability of Western military and economic backing, the terms on which — or whether — negotiations can end it, and whether Ukraine''s wartime governance holds up under the strain of corruption scandals. A fifth front runs through the energy system on both sides, targeting the fuel and power that sustain the other''s war effort. Coverage of the war is itself contested ground: the same events are described as full-scale invasion and national resistance in Kyiv and the West, and as a special military operation against NATO encroachment in Moscow.', editorial_summary_de='Russlands am 24. Februar 2022 begonnene Invasion der Ukraine ist der groesste Landkrieg in Europa seit 1945 und die praegende Tatsache der gegenwaertigen europaeischen Sicherheitsordnung. Vier Streitachsen durchziehen ihn: die Kontrolle ueber die Front selbst, Ausmass und Durchhaltefaehigkeit der westlichen militaerischen und wirtschaftlichen Unterstuetzung, die Bedingungen, unter denen — oder ob ueberhaupt — Verhandlungen den Krieg beenden koennen, sowie die Frage, ob die ukrainische Kriegsfuehrung der Belastung durch Korruptionsskandale standhaelt. Eine fuenfte Front verlaeuft durch das Energiesystem beider Seiten und zielt auf Treibstoff und Strom, die die Kriegsanstrengung der jeweils anderen Seite aufrechterhalten. Die Berichterstattung ueber den Krieg ist selbst umkaempftes Terrain: dieselben Ereignisse werden in Kiew und im Westen als umfassende Invasion und nationaler Widerstand beschrieben, in Moskau als militaerische Spezialoperation gegen die NATO-Osterweiterung.', centroid_ids=ARRAY['EUROPE-UKRAINE','EUROPE-RUSSIA'], primary_target='EUROPE-UKRAINE', affected_asset_ids=ARRAY['ukrainian_grain_belt','odesa_port','novorossiysk_port','druzhba_pipeline_west','turkish_straits','zaporizhzhia_npp','kerch_strait','omsk_refinery','primorsk_ust_luga_terminals'], member_fn_ids=ARRAY['ukraine_battlefield','western_aid_to_ukraine','ukraine_peace_negotiations','ukraine_official_corruption','ukraine_infrastructure_war'], fn_type='theater', is_active=true, display_order=6 WHERE id='ukraine_war_theater';
UPDATE friction_nodes SET name_en='Battlefield operations and territorial control', name_de='Kampfhandlungen und territoriale Kontrolle', description_en='The ground war itself: the contest for the front line and the territory behind it. Russian offensives and Ukrainian defense and counter-attacks across Donbas, Zaporizhzhia and the border oblasts -- captured villages, fortified towns, force generation and the daily attrition that moves the map by metres. Each side reads the same advance as either liberation or aggression, and that contest over meaning sits on top of the physical one.', description_de='Der Bodenkrieg selbst: der Kampf um die Frontlinie und das Land dahinter. Russische Offensiven sowie ukrainische Verteidigung und Gegenangriffe im Donbass, in Saporischschja und den Grenzregionen -- eroberte Doerfer, befestigte Staedte, Truppenaufwuchs und die taegliche Zermuerbung, die die Karte um Meter verschiebt. Jede Seite liest denselben Vorstoss entweder als Befreiung oder als Aggression, und dieser Streit um die Bedeutung liegt ueber dem physischen.', editorial_summary_en='This is the war at its most literal: kilometres of front, fortified towns that change hands over months, and an attritional grind that consumes men and materiel faster than either side admits. Russia presses a slow, costly advance framed as the liberation of historically Russian land; Ukraine fights a defensive war of national survival, trading space for time and striking back where it can. The battlefield''s vocabulary -- Pokrovsk, Kupiansk, Avdiivka, the Kursk incursion, mobilisation and casualty figures -- is where the war''s cost is counted most directly. Because the same kilometre is "liberated" by one side and "occupied" by the other, the ground war is also a contest over narrative: whose advance is legitimate, whose losses are catastrophic, and whether the line can move at all. Nothing else in the theatre -- aid, diplomacy, strikes -- makes sense except in relation to what is happening here.', editorial_summary_de='Dies ist der Krieg in seiner buchstaeblichsten Form: Kilometer Front, befestigte Staedte, die ueber Monate den Besitzer wechseln, und ein zermuerbender Abnutzungskampf, der Menschen und Material schneller verbraucht, als beide Seiten zugeben. Russland treibt einen langsamen, verlustreichen Vormarsch voran, gerahmt als Befreiung historisch russischen Landes; die Ukraine fuehrt einen defensiven Ueberlebenskrieg, tauscht Raum gegen Zeit und schlaegt zurueck, wo sie kann. Das Vokabular des Schlachtfelds -- Pokrowsk, Kupjansk, Awdijiwka, der Vorstoss bei Kursk, Mobilmachung und Verlustzahlen -- ist der Ort, an dem die Kosten des Krieges am unmittelbarsten gezaehlt werden. Weil derselbe Kilometer von der einen Seite "befreit" und von der anderen "besetzt" wird, ist der Bodenkrieg auch ein Streit ums Narrativ: wessen Vormarsch legitim ist, wessen Verluste katastrophal sind und ob sich die Linie ueberhaupt bewegen laesst. Nichts anderes im Kriegsschauplatz -- Hilfe, Diplomatie, Angriffe -- ergibt Sinn ausser im Verhaeltnis zu dem, was hier geschieht.', centroid_ids=ARRAY['EUROPE-UKRAINE','EUROPE-RUSSIA'], primary_target=NULL, affected_asset_ids='{}', member_fn_ids=NULL, fn_type='atomic', is_active=true, display_order=20 WHERE id='ukraine_battlefield';
UPDATE friction_nodes SET name_en='Western military and economic aid to Ukraine', name_de='Westliche Militaer- und Wirtschaftshilfe fuer die Ukraine', description_en='The flow of Western military, financial and industrial support that keeps Ukraine in the fight -- weapons packages, air defense, artillery and ammunition, budget financing and the fight over frozen Russian assets. The contested question is not only how much to send but what it buys: a sustainable defense, or an open-ended commitment that deepens the West''s exposure.', description_de='Der Strom westlicher militaerischer, finanzieller und industrieller Unterstuetzung, der die Ukraine im Kampf haelt -- Waffenpakete, Luftverteidigung, Artillerie und Munition, Haushaltsfinanzierung und der Streit um eingefrorene russische Vermoegenswerte. Die umstrittene Frage ist nicht nur, wie viel geschickt wird, sondern was es erkauft: eine tragfaehige Verteidigung oder eine unbefristete Verpflichtung, die die Exponierung des Westens vertieft.', editorial_summary_en='Ukraine cannot fight without external supply, which makes Western aid a front in its own right -- fought in the parliaments and treasuries of Washington, Brussels, Berlin, London and Paris as much as on the battlefield. Supporters frame aid as the cheapest possible investment in European security: sustaining a democracy under attack and degrading a strategic rival without a single NATO soldier. Critics -- from the American right to Global South commentators -- read the same flows as escalation, proxy waste and a subsidy to prolong an unwinnable war. The specifics matter: which systems (air-defense interceptors, long-range strike, F-16s), how they are financed (direct grants, loans, the disputed use of immobilised Russian central-bank assets), and whether European industry can backfill what American politics may withdraw. Aid is where the war''s staying power is ultimately decided -- and where Western unity is most visibly tested.', editorial_summary_de='Die Ukraine kann ohne externen Nachschub nicht kaempfen, was die westliche Hilfe zu einer eigenen Front macht -- ausgetragen in den Parlamenten und Finanzministerien von Washington, Bruessel, Berlin, London und Paris ebenso wie auf dem Schlachtfeld. Befuerworter rahmen Hilfe als die billigstmoegliche Investition in europaeische Sicherheit: eine angegriffene Demokratie stuetzen und einen strategischen Rivalen schwaechen, ohne einen einzigen NATO-Soldaten. Kritiker -- von der amerikanischen Rechten bis zu Kommentatoren des Globalen Suedens -- lesen dieselben Stroeme als Eskalation, Stellvertreter-Verschwendung und Subvention zur Verlaengerung eines nicht zu gewinnenden Krieges. Die Einzelheiten zaehlen: welche Systeme (Abfangraketen der Luftverteidigung, Langstreckenschlag, F-16), wie sie finanziert werden (Direktzuschuesse, Kredite, die umstrittene Nutzung immobilisierter russischer Zentralbankvermoegen) und ob die europaeische Industrie auffuellen kann, was die amerikanische Politik moeglicherweise zurueckzieht. An der Hilfe entscheidet sich letztlich das Durchhaltevermoegen des Krieges -- und hier wird die westliche Einheit am sichtbarsten auf die Probe gestellt.', centroid_ids=ARRAY['EUROPE-UKRAINE','AMERICAS-USA','EUROPE-UK','EUROPE-FRANCE','EUROPE-GERMANY'], primary_target='EUROPE-UKRAINE', affected_asset_ids='{}', member_fn_ids=NULL, fn_type='atomic', is_active=true, display_order=21 WHERE id='western_aid_to_ukraine';
UPDATE friction_nodes SET name_en='Peace negotiations and diplomatic initiatives', name_de='Friedensverhandlungen und diplomatische Initiativen', description_en='The diplomatic track: ceasefire proposals, security guarantees, territorial formulas and the shuttle diplomacy around them. Three incompatible end-states compete -- a Ukrainian restoration of 1991 borders, a Russian settlement that ratifies its annexations and Ukrainian neutrality, and a great-power push to freeze the line as it stands. The contest is over whose terms define "peace".', description_de='Die diplomatische Spur: Waffenstillstandsvorschlaege, Sicherheitsgarantien, territoriale Formeln und die Pendeldiplomatie darum herum. Drei unvereinbare Endzustaende konkurrieren -- eine ukrainische Wiederherstellung der Grenzen von 1991, eine russische Regelung, die seine Annexionen und die ukrainische Neutralitaet bestaetigt, und ein Grossmacht-Vorstoss, die Linie im heutigen Verlauf einzufrieren. Der Streit geht darum, wessen Bedingungen "Frieden" definieren.', editorial_summary_en='Every settlement proposal encodes a theory of who is winning. Kyiv''s maximalist position -- full withdrawal, restored borders, accountability and NATO-backed guarantees -- treats negotiation as the codification of a Russian defeat that has not yet happened on the ground. Moscow''s terms invert this: recognised annexations, a neutral and "denazified" Ukraine, sanctions lifted -- the ratification of its war aims by other means. Between them sits a third track, pushed at various points by Washington and echoed by war-weary European and Global South voices, that would freeze the front roughly where it lies and defer the hardest questions. The vocabulary -- Istanbul, Anchorage, security guarantees, line of contact, territorial swaps -- shifts with each round of shuttle diplomacy, but the underlying deadlock is stable: no party will sign terms that concede what it still believes it can win or hold. Diplomacy here is less a path out of the war than another arena in which it is fought.', editorial_summary_de='Jeder Regelungsvorschlag verschluesselt eine Theorie darueber, wer gewinnt. Kiews maximalistische Position -- vollstaendiger Abzug, wiederhergestellte Grenzen, Rechenschaft und NATO-gestuetzte Garantien -- behandelt Verhandlungen als Festschreibung einer russischen Niederlage, die am Boden noch nicht eingetreten ist. Moskaus Bedingungen kehren dies um: anerkannte Annexionen, eine neutrale und "entnazifizierte" Ukraine, aufgehobene Sanktionen -- die Bestaetigung seiner Kriegsziele mit anderen Mitteln. Dazwischen liegt eine dritte Spur, zeitweise von Washington vorangetrieben und von kriegsmueden europaeischen und Global-South-Stimmen aufgegriffen, die die Front etwa dort einfrieren wuerde, wo sie verlaeuft, und die haertesten Fragen vertagt. Das Vokabular -- Istanbul, Anchorage, Sicherheitsgarantien, Kontaktlinie, Gebietstausch -- verschiebt sich mit jeder Runde der Pendeldiplomatie, doch die zugrunde liegende Blockade ist stabil: keine Partei unterzeichnet Bedingungen, die preisgeben, was sie noch zu gewinnen oder zu halten glaubt. Diplomatie ist hier weniger ein Weg aus dem Krieg als eine weitere Arena, in der er gefuehrt wird.', centroid_ids=ARRAY['EUROPE-UKRAINE','EUROPE-RUSSIA','AMERICAS-USA','NON-STATE-EU'], primary_target='EUROPE-UKRAINE', affected_asset_ids='{}', member_fn_ids=NULL, fn_type='atomic', is_active=true, display_order=22 WHERE id='ukraine_peace_negotiations';
UPDATE friction_nodes SET name_en='Official corruption and reconstruction challenges', name_de='Amtliche Korruption und Herausforderungen des Wiederaufbaus', description_en='Governance under wartime stress: graft investigations, procurement scandals and the integrity of reconstruction and aid spending. Coverage splits three ways -- reform institutions proving they work, Western allies alarmed that high-level corruption threatens support, and adversary media casting the whole state as a kleptocracy stealing aid at scale.', description_de='Regieren unter Kriegsbelastung: Korruptionsermittlungen, Beschaffungsskandale und die Integritaet der Ausgaben fuer Wiederaufbau und Hilfe. Die Berichterstattung teilt sich in drei Richtungen -- Reforminstitutionen, die ihre Wirksamkeit beweisen, westliche Verbuendete, die alarmiert sind, dass Korruption auf hoher Ebene die Unterstuetzung gefaehrdet, und gegnerische Medien, die den gesamten Staat als Kleptokratie darstellen, die Hilfe in grossem Stil stiehlt.', editorial_summary_en='Corruption is the one Ukraine topic where the usual publisher coalitions break down. The country''s own anti-corruption architecture -- NABU, SAPO, the High Anti-Corruption Court -- is both a genuine reform success and a steady source of damaging headlines, because every prosecution is also proof that the graft was there. Supportive outlets can therefore read the same Yermak-circle or procurement scandal two ways at once: as institutions working, or as systemic rot that endangers the Western aid the war depends on. That is why this node runs a three-stance gradient rather than a simple pro/con split -- reform-in-progress, Western systemic alarm, and the adversary "Zelensky kleptocracy" frame that treats every story as evidence aid is being stolen wholesale. The stakes are concrete: corruption narratives feed directly into the aid debate, so a single high-profile scandal can move votes in Washington and Brussels as much as any battlefield setback.', editorial_summary_de='Korruption ist das eine Ukraine-Thema, bei dem die ueblichen Publisher-Koalitionen zusammenbrechen. Die eigene Antikorruptionsarchitektur des Landes -- NABU, SAPO, der Hohe Antikorruptionsgerichtshof -- ist zugleich ein echter Reformerfolg und eine bestaendige Quelle schaedlicher Schlagzeilen, denn jede Strafverfolgung ist auch ein Beleg, dass die Korruption vorhanden war. Wohlwollende Medien koennen denselben Skandal im Jermak-Kreis oder bei der Beschaffung daher auf zweierlei Weise zugleich lesen: als funktionierende Institutionen oder als systemische Faeulnis, die die westliche Hilfe gefaehrdet, von der der Krieg abhaengt. Deshalb faehrt dieser Knoten einen Drei-Stufen-Gradienten statt einer einfachen Pro/Contra-Teilung -- Reform im Gange, westliche systemische Alarmierung und das gegnerische "Selenskyj-Kleptokratie"-Framing, das jede Geschichte als Beweis wertet, dass Hilfe in grossem Stil gestohlen wird. Die Einsaetze sind konkret: Korruptionsnarrative fliessen direkt in die Hilfsdebatte ein, sodass ein einziger prominenter Skandal in Washington und Bruessel ebenso Stimmen bewegen kann wie ein Rueckschlag auf dem Schlachtfeld.', centroid_ids=ARRAY['EUROPE-UKRAINE'], primary_target=NULL, affected_asset_ids='{}', member_fn_ids=NULL, fn_type='atomic', is_active=true, display_order=23 WHERE id='ukraine_official_corruption';
UPDATE friction_nodes SET name_en='The long-range war: strikes on energy, industry and infrastructure', name_de='Der Fernkrieg: Angriffe auf Energie, Industrie und Infrastruktur', description_en='The war fought past the front line, in both directions: Ukrainian long-range strikes on Russian refineries, fuel depots, export terminals, airbases and military industry; Russian missile and drone campaigns against Ukraine''s power system, fuel storage and cities; and the contested safety of the Zaporizhzhia nuclear plant. Energy and infrastructure are dual-use by nature -- each side presents its own strikes as military necessity and the other side''s as terror, and that contest over intent is part of the phenomenon itself.', description_de='Der Krieg jenseits der Frontlinie, in beide Richtungen: ukrainische Langstreckenangriffe auf russische Raffinerien, Treibstofflager, Exportterminals, Luftwaffenstuetzpunkte und Ruestungsindustrie; russische Raketen- und Drohnenkampagnen gegen das ukrainische Stromsystem, Treibstofflager und Staedte; dazu die umkaempfte Sicherheit des Kernkraftwerks Saporischschja. Energie und Infrastruktur sind ihrem Wesen nach dual-use -- jede Seite stellt eigene Angriffe als militaerische Notwendigkeit dar und die der Gegenseite als Terror; dieser Streit um die Absicht ist Teil des Phaenomens selbst.', editorial_summary_en='Since 2024 the war''s most distinctive strategic layer has moved off the front line and onto the energy map. Ukraine''s deep-strike campaign reaches refineries, depots and export terminals far inside Russia; Russia''s missile and drone campaign works through Ukraine''s grid, generation and fuel storage. Both campaigns hit systems that are irreducibly dual-use: the same refinery fuels tanks and tractors, the same grid powers arms plants and apartment blocks. Each side states a military-economic rationale for its own strikes -- degrading the enemy''s fuel supply, logistics and defence industry -- and frames the other''s as terror against civilians; adjudicating between those readings is the narratives'' job, not this node''s. The Zaporizhzhia plant sits at the centre as a standing nuclear-safety flashpoint, with the IAEA as the only institutional referee on site. The contest is fought as much over legitimacy as over megawatts.', editorial_summary_de='Seit 2024 hat sich die praegendste strategische Ebene des Krieges von der Front auf die Energiekarte verlagert. Die ukrainische Tiefschlag-Kampagne erreicht Raffinerien, Lager und Exportterminals weit im russischen Hinterland; die russische Raketen- und Drohnenkampagne richtet sich gegen das ukrainische Stromnetz, die Erzeugung und die Treibstofflager. Beide Kampagnen treffen Systeme, die unaufloeslich dual-use sind: dieselbe Raffinerie betankt Panzer und Traktoren, dasselbe Netz versorgt Ruestungswerke und Wohnbloecke. Jede Seite nennt fuer die eigenen Angriffe eine militaerisch-oekonomische Begruendung -- Schwaechung von Treibstoffversorgung, Logistik und Ruestungsindustrie des Gegners -- und rahmt die der Gegenseite als Terror gegen Zivilisten; zwischen diesen Lesarten zu entscheiden ist Aufgabe der Narrative, nicht dieses Knotens. Das Kernkraftwerk Saporischschja steht im Zentrum als permanenter nuklearer Gefahrenherd, mit der IAEO als einzigem institutionellen Schiedsrichter vor Ort. Der Konflikt wird ebenso um Legitimitaet wie um Megawatt gefuehrt.', centroid_ids=ARRAY['EUROPE-UKRAINE','EUROPE-RUSSIA'], primary_target=NULL, affected_asset_ids='{}', member_fn_ids=NULL, fn_type='atomic', is_active=true, display_order=5 WHERE id='ukraine_infrastructure_war';

UPDATE narratives_v2 SET name_en='Ukraine-aligned: defending the front, liberating territory', name_de='Ukraine-orientiert: Verteidigung der Front, Befreiung von Territorium', claim_en='Ukrainian and Western coverage frames the ground war as a legitimate national defense: holding the line against Russian assaults, counterattacking where possible, and liberating occupied territory. Coverage emphasises the defense of front-line cities, the cost of Russian offensives, and Ukrainian tactical adaptation (drones, fortifications, mobile defense).', claim_de='Ukrainische und westliche Berichterstattung rahmt den Bodenkrieg als legitime nationale Verteidigung: die Front gegen russische Angriffe halten, wo moeglich kontern und besetztes Territorium befreien. Im Fokus stehen die Verteidigung der Frontstaedte, der Preis der russischen Offensiven und die taktische Anpassung der Ukrainer (Drohnen, Befestigungen, bewegliche Verteidigung).', actor_centroids=ARRAY['EUROPE-UKRAINE','EUROPE-UK','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-BALTIC','EUROPE-VISEGRAD','AMERICAS-USA'], framing_keywords=ARRAY['liberation','counteroffensive','hold the line','defense of positions','territorial control','liberated','repelled assault','defenders','fortifications','tactical adaptation'], publishers=ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Le Figaro','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Tagesschau','Deutsche Welle','La Repubblica','Corriere della Sera','ANSA','El País','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','Defense News','Janes','Sky News','CNN','New York Times','Washington Post','Wall Street Journal','Politico'], fn_id='ukraine_battlefield', display_order=1, stance_label_en='Legitimate defense of the front', stance_label_de='Legitime Verteidigung der Front', stance=2, framing_required=false, is_active=true WHERE id='ukrainian_defense_and_deep_strikes';
UPDATE narratives_v2 SET name_en='Russia-aligned: the special military operation advancing -- liberation of Donbass', name_de='Russland-orientiert: die Spezialoperation rueckt vor -- Befreiung des Donbass', claim_en='Russian state press frames the ground war as the special military operation methodically achieving its territorial objectives: liberation of Donbass settlements, encirclement of Ukrainian groupings, and steady advances despite Western-supplied weaponry. Coverage emphasises Russian tactical superiority, Ukrainian manpower crises, and the inevitability of Russia''s territorial consolidation.', claim_de='Russische Staatsmedien rahmen den Bodenkrieg als militaerische Spezialoperation, die ihre territorialen Ziele methodisch erreicht: Befreiung der Donbass-Ortschaften, Einkesselung ukrainischer Gruppierungen und stetiges Vorruecken trotz westlicher Waffenlieferungen. Im Fokus stehen russische taktische Ueberlegenheit, ukrainische Personalkrisen und die Unausweichlichkeit der territorialen Konsolidierung Russlands.', actor_centroids=ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'], framing_keywords=ARRAY['liberation of Donbass','advance','encirclement','cauldron','territorial gains','special military operation','demilitarisation','Novorossiya','manpower crisis','front collapse'], publishers=ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV'], fn_id='ukraine_battlefield', display_order=2, stance_label_en='SMO territorial progress', stance_label_de='Territoriale Fortschritte der Spezialoperation', stance= -2, framing_required=false, is_active=true WHERE id='russian_smo_operations';
UPDATE narratives_v2 SET name_en='Ukraine-aligned: precision degradation of Russia''s war economy; Russian grid strikes are terror', name_de='Ukraine-orientiert: praezise Zermuerbung der russischen Kriegswirtschaft; russische Netzangriffe sind Terror', claim_en='Strikes on refineries, depots, export terminals and rear military industry are lawful pressure on the aggressor''s war economy and export revenue. It is Russia that weaponises winter by destroying Ukraine''s power grid, striking residential areas far from the front, and holding Europe hostage at the Zaporizhzhia plant.', claim_de='Angriffe auf Raffinerien, Treibstofflager, Exportterminals und die ruecwaertige Ruestungsindustrie sind rechtmaessiger Druck auf die Kriegswirtschaft und Exporterloese des Aggressors. Es ist Russland, das den Winter zur Waffe macht, indem es das ukrainische Stromnetz zerstoert, Wohngebiete fernab der Front beschiesst und Europa am Kernkraftwerk Saporischschja in Geiselhaft haelt.', actor_centroids=ARRAY['EUROPE-UKRAINE','AMERICAS-USA','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','NON-STATE-EU'], framing_keywords=ARRAY['war economy','legitimate military target','fuel shortage','gasoline crisis','kinetic sanctions','export revenue','weaponising winter','nuclear blackmail','refinery fire','deep strike'], publishers=ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Le Figaro','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Tagesschau','Deutsche Welle','La Repubblica','Corriere della Sera','ANSA','El País','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','Defense News','Janes','Sky News','CNN','New York Times','Washington Post','Wall Street Journal','Politico'], fn_id='ukraine_infrastructure_war', display_order=1, stance_label_en='Legitimate strikes on the war economy', stance_label_de='Legitime Schlaege gegen die Kriegswirtschaft', stance=2, framing_required=false, is_active=true WHERE id='infrastructure_war_economy_strikes';
UPDATE narratives_v2 SET name_en='Russia-aligned: Kyiv attacks civilian energy and endangers nuclear safety', name_de='Russland-orientiert: Kiew greift zivile Energie an und gefaehrdet die nukleare Sicherheit', claim_en='Ukrainian drone and missile attacks on refineries, pipelines and the Zaporizhzhia plant are terrorism against civilian infrastructure, enabled by Western targeting support. Russian strikes on energy facilities serve a military purpose: undermining Ukraine''s military-industrial complex, its logistics and the fuel supply to the front.', claim_de='Ukrainische Drohnen- und Raketenangriffe auf Raffinerien, Pipelines und das Kernkraftwerk Saporischschja sind Terror gegen zivile Infrastruktur, ermoeglicht durch westliche Zielunterstuetzung. Russische Schlaege gegen Energieanlagen dienen einem militaerischen Zweck: der Schwaechung des ukrainischen militaerisch-industriellen Komplexes, seiner Logistik und der Treibstoffversorgung der Front.', actor_centroids=ARRAY['EUROPE-RUSSIA'], framing_keywords=ARRAY['terrorist attack','civilian infrastructure','energy terror','provocation','nuclear catastrophe','Kyiv regime','Western targeting data','retaliatory strike'], publishers=ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV'], fn_id='ukraine_infrastructure_war', display_order=2, stance_label_en='Terror against civilian infrastructure', stance_label_de='Terror gegen zivile Infrastruktur', stance= -2, framing_required=false, is_active=true WHERE id='infrastructure_war_energy_terror';
UPDATE narratives_v2 SET name_en='Ukrainian anti-corruption institutions are investigating and prosecuting successfully', name_de='Ukrainische Antikorruptions-Institutionen ermitteln und verfolgen erfolgreich', claim_en='Reform-progress framing (Ukrainian reformist press + Western mainstream + EU policy outlets) treats ongoing corruption investigations as evidence that Ukrainian anti-corruption infrastructure built since 2014 is functioning under wartime stress. Coverage tracks NABU, SAP, HACC, and NACP investigations of senior officials including Presidential Office personnel, defense procurement scandals, and regional governors. Vocabulary: anti-corruption infrastructure, institutional independence, reform progress, EU conditionality met, IMF benchmark, transparency, accountability, audit. Coverage frames Western audit demands as legitimate and constructive, presents prosecutions of senior officials as proof of independence from the Presidential Office, and contextualises scandals within the broader institutional transformation since 2014. Prescription: sustain institutional protection from political interference; maintain Western conditionality leverage; complete judicial reform; continue prosecuting irrespective of rank.', claim_de='Reform-Fortschritts-Rahmung (ukrainische Reformmedien + westlicher Mainstream + EU-Politik-Medien) behandelt laufende Korruptionsermittlungen als Beleg, dass die seit 2014 aufgebaute ukrainische Antikorruptions-Infrastruktur unter Kriegsbelastung funktioniert. Berichterstattung verfolgt NABU-, SAP-, HACC- und NACP-Ermittlungen gegen hochrangige Beamte einschliesslich Personal des Praesidialamts, Ruestungsbeschaffungs-Skandale und Regional-Gouverneure. Vokabular: Antikorruptions-Infrastruktur, institutionelle Unabhaengigkeit, Reformfortschritt, EU-Konditionalitaet erfuellt, IWF-Massstab, Transparenz, Rechenschaft, Audit. Berichterstattung rahmt westliche Audit-Forderungen als legitim und konstruktiv, praesentiert Strafverfolgung hochrangiger Beamter als Beleg fuer Unabhaengigkeit vom Praesidialamt und kontextualisiert Skandale in der breiteren institutionellen Transformation seit 2014. Vorschrift: institutionellen Schutz vor politischer Einmischung aufrechterhalten; westliche Konditionalitaets-Hebel aufrechterhalten; Justizreform vollenden; Strafverfolgung unabhaengig vom Rang fortsetzen.', actor_centroids=ARRAY['EUROPE-UKRAINE','AMERICAS-USA','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','NON-STATE-EU'], framing_keywords=ARRAY['reform progress','institutional independence','restored independence','agency autonomy','defended independence','anti-corruption reform','EU praises','IMF benchmark','judicial reform','functioning institutions','proof of independence','Reformfortschritt','Unabhängigkeit der Behörden','Antikorruptionsreform','wiederhergestellte Unabhängigkeit'], publishers=ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Deutsche Welle','La Repubblica','ANSA','El País','ERR News','LRT English','Atlantic Council','Associated Press','The Economist','EurActiv','New York Times','Washington Post','Wall Street Journal','Politico'], fn_id='ukraine_official_corruption', display_order=1, stance_label_en='Reform progress under wartime stress', stance_label_de='Reformfortschritt unter Kriegsbelastung', stance=1, framing_required=true, is_active=true WHERE id='reform_in_progress';
UPDATE narratives_v2 SET name_en='Western alarm: high-level corruption threatens Ukraine credibility and aid', name_de='Westliche Alarmierung: Korruption auf höchster Ebene gefährdet Glaubwürdigkeit und Hilfe', claim_en='Systemic-alarm framing (Western mainstream + reformist Ukrainian press) treats high-level corruption cases -- reaching the Presidential Office and figures like Yermak -- as a threat to Ukraine credibility, Western aid, and EU accession, rather than proof that institutions work. Distinct from Russian-state endemic-corruption framing: it does not call the state illegitimate or aid categorically stolen, but expresses genuine concern from Ukraine supporters. Vocabulary: corruption scandal, case widens, probe escalates, reaches the top, inner circle, chief of staff, survives for now, wartime graft, threatens aid, credibility.', claim_de='Systemische-Alarm-Rahmung (westlicher Mainstream + reformorientierte ukrainische Presse) behandelt Korruptionsfälle auf höchster Ebene -- bis ins Präsidialbüro und zu Figuren wie Jermak -- als Bedrohung für Glaubwürdigkeit, westliche Hilfe und EU-Beitritt, nicht als Beweis funktionierender Institutionen. Anders als die russische Rahmung erklärt sie den Staat nicht für illegitim.', actor_centroids=ARRAY['EUROPE-UKRAINE','AMERICAS-USA','EUROPE-GERMANY','EUROPE-FRANCE','EUROPE-UK','NON-STATE-EU'], framing_keywords=ARRAY['corruption scandal','corruption affair','corruption case','case widens','probe widens','probe escalates','corruption probe','high-level corruption','reaches the top','inner circle','chief of staff','ex-chief of staff','right-hand man','survives','for now','wartime graft','embezzlement','stolen aid','deep-rooted','credibility','threatens aid','how corrupt','gut anti-corruption','curb anti-corruption','undermine anti-corruption','Yermak','Mindich','Korruptionsaffäre','Korruptionsskandal','Korruptionsfall','wie korrupt','tiefe Fall','Ex-Stabschef','Stabschef','Jermak','übersteht'], publishers=ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Deutsche Welle','La Repubblica','ANSA','El País','ERR News','LRT English','Atlantic Council','Associated Press','The Economist','EurActiv','New York Times','Washington Post','Wall Street Journal','Politico'], fn_id='ukraine_official_corruption', display_order=2, stance_label_en='Western alarm at systemic corruption', stance_label_de='Westliche Alarmierung über systemische Korruption', stance= -1, framing_required=true, is_active=true WHERE id='western_systemic_alarm';
UPDATE narratives_v2 SET name_en='Zelensky inner circle is systemically corrupt; Western aid is being stolen at scale', name_de='Der Selenskyj-Kreis ist systemisch korrupt; westliche Hilfe wird in grossem Stil gestohlen', claim_en='Endemic-corruption framing (Russian state press + Western contrarian + Global South + some Hungarian-aligned EU) treats the same investigations and scandals as confirmation that the Zelensky inner circle is systemically corrupt, that Western aid is being stolen at scale through defense procurement, that the regime is increasingly authoritarian (banned opposition parties, restricted media, cancelled elections, Yermak-centred power concentration), and that EU/NATO accession on this institutional basis is unrealistic. Vocabulary: endemic corruption, regime corruption, stolen aid, defense procurement scandal, Yermak inner circle, authoritarian regime, cancelled elections, banned opposition, Western blind eye. Coverage uses the same anti-corruption agency investigations as evidence of scale, frames prosecutions as theatrical or selective, and emphasises Western media protection of the regime. Prescription: condition or halt aid pending genuine accountability; recognise that the regime cannot deliver promised reforms; reject any settlement that consolidates the current Kyiv leadership.', claim_de='Endemisch-Korruptions-Rahmung (russische Staatsmedien + westliche Dissidenten + Global South + einige ungarisch-orientierte EU) behandelt dieselben Ermittlungen und Skandale als Bestaetigung, dass der Selenskyj-Kreis systemisch korrupt sei, westliche Hilfe in grossem Stil ueber Ruestungsbeschaffung gestohlen werde, das Regime zunehmend autoritaer sei (verbotene Oppositionsparteien, eingeschraenkte Medien, abgesagte Wahlen, Jermak-zentrierte Machtkonzentration) und EU/NATO-Beitritt auf dieser institutionellen Basis unrealistisch. Vokabular: endemische Korruption, Regime-Korruption, gestohlene Hilfe, Ruestungsbeschaffungs-Skandal, Jermak-Innenkreis, autoritaeres Regime, abgesagte Wahlen, verbotene Opposition, westliches Wegschauen. Berichterstattung nutzt dieselben Antikorruptionsbehoerden-Ermittlungen als Belegmaterial fuer das Ausmass, rahmt Strafverfolgung als theatralisch oder selektiv und betont westlichen Medienschutz des Regimes. Vorschrift: Hilfe an echte Rechenschaft konditionieren oder einstellen; anerkennen, dass das Regime versprochene Reformen nicht liefern kann; jede Beilegung ablehnen, die die gegenwaertige Kiewer Fuehrung konsolidiert.', actor_centroids=ARRAY['EUROPE-RUSSIA','ASIA-CHINA'], framing_keywords=ARRAY['endemic corruption','regime corruption','stolen aid','defense procurement scandal','Yermak inner circle','authoritarian regime','cancelled elections','banned opposition','Western blind eye','theatrical prosecution','selective justice'], publishers=ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV','Fox News','Global Times','CGTN','China Daily','Hindustan Times','TRT World','Daily Sabah','O Globo'], fn_id='ukraine_official_corruption', display_order=3, stance_label_en='Zelensky regime endemic corruption', stance_label_de='Endemische Korruption im Selenskyj-Regime', stance= -2, framing_required=false, is_active=true WHERE id='zelensky_regime_corruption';
UPDATE narratives_v2 SET name_en='Just peace requires full Russian withdrawal to 1991 borders with NATO-backed security guarantees', name_de='Gerechter Frieden erfordert vollen russischen Rueckzug zu Grenzen von 1991 mit NATO-gestuetzten Sicherheitsgarantien', claim_en='Ukrainian maximalist framing (Ukrainian press + Western mainstream + Eastern European hawks + EU centrists, with internal disagreement chiefly from Hungary and Slovakia) holds that just peace requires full Russian withdrawal to internationally recognised 1991 borders, NATO accession or equivalent binding security guarantees, accountability mechanisms for war crimes, and reparations funded through seized Russian sovereign assets. Vocabulary: just peace, territorial integrity, 1991 borders, NATO accession, security guarantees, accountability, no appeasement, reparations, war crimes tribunal. Coverage rejects any framework that legitimises territorial losses, frames the 2014 Crimea precedent as proof that frozen conflicts invite further aggression, and emphasises Ukrainian society''s rejection of compromise terms. Prescription: continue military pressure until Russian retreat; refuse settlement frameworks that recognise annexations; pre-condition negotiations on Russian withdrawal.', claim_de='Ukrainische Maximalrahmung (ukrainische Medien + westlicher Mainstream + osteuropaeische Falken + EU-Zentristen, mit internen Differenzen vor allem aus Ungarn und der Slowakei) haelt fest, dass gerechter Frieden vollen russischen Rueckzug zu international anerkannten Grenzen von 1991, NATO-Beitritt oder gleichwertige verbindliche Sicherheitsgarantien, Rechenschaftsmechanismen fuer Kriegsverbrechen und Reparationen aus beschlagnahmtem russischen Staatsvermoegen erfordere. Vokabular: gerechter Frieden, territoriale Integritaet, Grenzen von 1991, NATO-Beitritt, Sicherheitsgarantien, Rechenschaft, keine Beschwichtigung, Reparationen, Kriegsverbrechertribunal. Berichterstattung lehnt jeden Rahmen ab, der territoriale Verluste legitimiert, rahmt den Krim-Praezedenzfall 2014 als Beleg, dass eingefrorene Konflikte weitere Aggression provozieren, und betont die Ablehnung von Kompromissbedingungen in der ukrainischen Gesellschaft. Vorschrift: militaerischen Druck bis zum russischen Rueckzug fortsetzen; Beilegungsrahmen ablehnen, die Annexionen anerkennen; Verhandlungen an russischen Rueckzug vor-konditionieren.', actor_centroids=ARRAY['EUROPE-BALTIC','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-UK','EUROPE-UKRAINE','EUROPE-VISEGRAD','NON-STATE-EU'], framing_keywords=ARRAY['just peace','territorial integrity','1991 borders','NATO accession','security guarantees','accountability','no appeasement','reparations','war crimes tribunal','rule of law','frozen conflict trap','reward aggression','full withdrawal'], publishers=ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Le Figaro','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Tagesschau','Deutsche Welle','La Repubblica','Corriere della Sera','ANSA','El País','Die Presse','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','The Economist','EurActiv','iROZHLAS','Novinite'], fn_id='ukraine_peace_negotiations', display_order=1, stance_label_en='Ukrainian maximalist demands', stance_label_de='Ukrainische Maximalforderungen', stance=2, framing_required=false, is_active=true WHERE id='ukrainian_maximalist_peace';
UPDATE narratives_v2 SET name_en='Settlement must complete all SMO objectives: denazification, demilitarisation, neutrality, recognised annexations, lifted sanctions', name_de='Beilegung muss alle SMO-Ziele vollenden: Entnazifizierung, Entmilitarisierung, Neutralitaet, anerkannte Annexionen, aufgehobene Sanktionen', claim_en='Russian maximalist framing (Russian state press + Belarusian state) holds that any settlement must address the root causes of the war by achieving all stated objectives of the special military operation. The framework: complete denazification of Ukrainian leadership and institutions, demilitarisation of the Ukrainian Armed Forces to defined caps, formal constitutional neutrality (no NATO accession ever, no foreign bases), formal international recognition of all four annexed regions (Donetsk, Luhansk, Zaporizhzhia, Kherson) plus Crimea within their claimed administrative boundaries, full restoration of Russian-language rights, complete lifting of all sanctions, return of all frozen sovereign assets, and a binding US/NATO commitment to no further eastern expansion. Vocabulary: SMO objectives, root causes, denazification, demilitarisation, constitutional neutrality, recognised borders, Russian-speaking rights, sanctions lifted, frozen assets returned, NATO non-expansion guarantee, multipolar settlement. Prescription: any settlement that does not deliver these objectives is unacceptable; negotiations are useful only as a venue to achieve them; military operations continue until objectives are met or accepted at the negotiating table.', claim_de='Russische Maximalrahmung (russische Staatsmedien + belarussische Staatsmedien) haelt fest, dass jede Beilegung die Grundursachen des Krieges adressieren und alle erklaerten Ziele der militaerischen Spezialoperation erreichen muesse. Das Rahmenwerk: vollstaendige Entnazifizierung der ukrainischen Fuehrung und Institutionen, Entmilitarisierung der ukrainischen Streitkraefte auf festgelegte Obergrenzen, formale verfassungsrechtliche Neutralitaet (kein NATO-Beitritt jemals, keine auslaendischen Basen), formale internationale Anerkennung aller vier annektierten Regionen (Donezk, Luhansk, Saporischschja, Cherson) plus Krim innerhalb ihrer beanspruchten Verwaltungsgrenzen, volle Wiederherstellung russischer Sprachrechte, vollstaendige Aufhebung aller Sanktionen, Rueckgabe allen eingefrorenen Staatsvermoegens und verbindliche US/NATO-Verpflichtung zu keiner weiteren Osterweiterung. Vokabular: SMO-Ziele, Grundursachen, Entnazifizierung, Entmilitarisierung, verfassungsrechtliche Neutralitaet, anerkannte Grenzen, russische Sprachrechte, aufgehobene Sanktionen, zurueckgegebenes Vermoegen, NATO-Nichterweiterungs-Garantie, multipolare Beilegung. Vorschrift: jede Beilegung ohne diese Ziele ist unannehmbar; Verhandlungen sind nur als Ort sinnvoll, sie zu erreichen; Militaeroperationen werden fortgesetzt, bis Ziele erreicht oder am Verhandlungstisch akzeptiert sind.', actor_centroids=ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'], framing_keywords=ARRAY['SMO objectives','root causes','denazification','demilitarisation','constitutional neutrality','recognised borders','Russian-speaking rights','sanctions lifted','frozen assets returned','NATO non-expansion','multipolar settlement','our people','brotherly people','no NATO accession ever'], publishers=ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV'], fn_id='ukraine_peace_negotiations', display_order=2, stance_label_en='Russian maximalist demands (SMO objectives)', stance_label_de='Russische Maximalforderungen (SMO-Ziele)', stance= -2, framing_required=false, is_active=true WHERE id='russian_maximalist_peace';
UPDATE narratives_v2 SET name_en='End the killing through frozen line of contact + Ukrainian neutrality, without endorsing Russian maximalist goals', name_de='Toeten beenden durch eingefrorene Beruehrungslinie + ukrainische Neutralitaet, ohne russische Maximalziele zu billigen', claim_en='Frontline-freeze framing (Trump-aligned American press + Hungarian/Slovak-aligned EU + Turkish + Indian + Chinese + Brazilian + broader Global South) holds that the war is unwinnable for either side at acceptable cost and that a pragmatic settlement requires freezing the line of contact, formalising Ukrainian neutrality (no NATO accession), building a multilateral security guarantee structure outside NATO, lifting sanctions in phases tied to verified compliance, and allowing refugee return. Crucially, this position does NOT endorse Russian maximalist objectives — no demilitarisation of the Ukrainian Armed Forces, no denazification framework, no formal international recognition of annexed territories (de facto control accepted, de jure recognition deferred). The framework is closer to a Korean armistice than to a Russian victory. The Anchorage track (sometimes "spirit of Anchorage") refers to Trump-Putin diplomatic efforts to crystallise this position. Vocabulary: freeze, line of contact, Anchorage framework, neutrality (not demilitarisation), multilateral security, end the killing, Korean armistice, phased sanctions relief, sustainable peace, end the war. Prescription: immediate freeze; Istanbul-style talks; Ukrainian constitutional neutrality with security backstops outside NATO; phased sanctions relief tied to compliance.', claim_de='Frontlinien-Einfrierungs-Rahmung (Trump-orientierte amerikanische Medien + ungarisch/slowakisch-orientierte EU + tuerkisch + indisch + chinesisch + brasilianisch + breiterer Global South) haelt fest, dass der Krieg fuer beide Seiten zu akzeptablen Kosten nicht gewinnbar sei und eine pragmatische Beilegung Einfrieren der Beruehrungslinie, Formalisierung ukrainischer Neutralitaet (kein NATO-Beitritt), Aufbau multilateraler Sicherheitsgarantie-Struktur ausserhalb der NATO, phasenweise Sanktionserleichterung an verifizierte Einhaltung gebunden und Fluechtlingsrueckkehr erfordere. Entscheidend: diese Position billigt NICHT russische Maximalziele — keine Entmilitarisierung der ukrainischen Streitkraefte, kein Entnazifizierungsrahmen, keine formale internationale Anerkennung annektierter Territorien (de-facto-Kontrolle akzeptiert, de-jure-Anerkennung aufgeschoben). Der Rahmen ist naeher am koreanischen Waffenstillstand als an einem russischen Sieg. Die Anchorage-Spur (manchmal "Geist von Anchorage") verweist auf Trump-Putin-Diplomatie zur Verfestigung dieser Position. Vokabular: Einfrieren, Beruehrungslinie, Anchorage-Rahmen, Neutralitaet (nicht Entmilitarisierung), multilaterale Sicherheit, Toeten beenden, koreanischer Waffenstillstand, phasenweise Sanktionserleichterung, nachhaltiger Frieden, Krieg beenden. Vorschrift: sofortiges Einfrieren; Istanbul-Stil-Gespraeche; ukrainische verfassungsrechtliche Neutralitaet mit Sicherheitsabsicherungen ausserhalb der NATO; phasenweise Sanktionserleichterung an Einhaltung gebunden.', actor_centroids=ARRAY['AMERICAS-USA','ASIA-CHINA','ASIA-INDIA','MIDEAST-TURKEY','AMERICAS-BRAZIL'], framing_keywords=ARRAY['freeze','line of contact','current lines','Anchorage framework','spirit of Anchorage','neutrality','multilateral security','end the killing','Korean armistice','phased sanctions relief','sustainable peace','end the war','realistic settlement','negotiated end','de facto recognition'], publishers=ARRAY['Fox News','Global Times','CGTN','China Daily','Hindustan Times','Times of India','NDTV','The Hindu','WION','Dawn','Express Tribune','TRT World','Daily Sabah','Anadolu Agency','O Globo','Bangkok Post','BRICS Info','News24'], fn_id='ukraine_peace_negotiations', display_order=3, stance_label_en='Frontline freeze (Anchorage track)', stance_label_de='Einfrieren der Frontlinie (Anchorage-Spur)', stance= -1, framing_required=false, is_active=true WHERE id='frontline_freeze_settlement';
UPDATE narratives_v2 SET name_en='Ukraine''s war of national defense deserves full Western and democratic-world solidarity', name_de='Der ukrainische Verteidigungskrieg verdient volle westliche und demokratische Solidaritaet', claim_en='Ukrainian, Western mainstream, and Eastern European press frame the war as Ukraine''s war of national survival against unprovoked Russian aggression. Vocabulary centers on resistance, liberation, sovereign defense, solidarity, and the moral and strategic necessity of supporting Ukraine until Russian forces withdraw. Coverage emphasises Ukrainian agency and courage, Russian war crimes, the humanitarian cost of occupation, and the global stakes (precedent for territorial aggression, NATO credibility, rules-based order). Prescription: sustain and expand military, economic, and diplomatic support; hold Russia accountable; integrate Ukraine into Euro-Atlantic structures.', claim_de='Ukrainische, westliche Mainstream- und osteuropaeische Medien rahmen den Krieg als ukrainischen Ueberlebenskrieg gegen unprovozierte russische Aggression. Das Vokabular kreist um Widerstand, Befreiung, souveraene Verteidigung, Solidaritaet und die moralische sowie strategische Notwendigkeit, die Ukraine zu unterstuetzen, bis russische Truppen abziehen. Berichterstattung betont ukrainische Handlungsfaehigkeit und Mut, russische Kriegsverbrechen, humanitaere Kosten der Besatzung und globale Einsaetze (Praezedenz fuer territoriale Aggression, NATO-Glaubwuerdigkeit, regelbasierte Ordnung). Vorschrift: militaerische, wirtschaftliche und diplomatische Unterstuetzung aufrechterhalten und ausbauen; Russland zur Rechenschaft ziehen; Ukraine in euro-atlantische Strukturen integrieren.', actor_centroids=ARRAY['EUROPE-UKRAINE','EUROPE-UK','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-BALTIC','EUROPE-VISEGRAD','AMERICAS-USA'], framing_keywords=ARRAY['Russian aggression','unprovoked invasion','Ukrainian resistance','sovereign defense','rules-based order','war crimes','support Ukraine','solidarity','liberation','territorial integrity','accountability','democratic Ukraine','full-scale invasion','full-scale war','all-out war','total war','unprovoked full-scale','war of aggression'], publishers=ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Le Figaro','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Tagesschau','Handelsblatt','Deutsche Welle','La Repubblica','Corriere della Sera','ANSA','El País','Die Presse','Der Standard','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','The Economist','EurActiv','Novinite','Sky News','CNN','NPR','New York Times','Washington Post','Wall Street Journal','Politico','Defense News','iROZHLAS','eKathimerini'], fn_id='ukraine_war_theater', display_order=1, stance_label_en='Solidarity with Ukrainian resistance', stance_label_de='Solidaritaet mit ukrainischem Widerstand', stance=2, framing_required=false, is_active=true WHERE id='ukraine_resistance_solidarity';
UPDATE narratives_v2 SET name_en='Russia''s special military operation defends Russian-speaking populations from Western-backed Kyiv regime', name_de='Russlands militaerische Spezialoperation verteidigt russischsprachige Bevoelkerungen gegen das vom Westen gestuetzte Kiewer Regime', claim_en='Russian state press and aligned outlets frame the war as a defensive special military operation (SMO) protecting Russian-speaking populations in Donbas and Crimea from a Western-installed regime in Kyiv that pursued ethnic discrimination and NATO encroachment since 2014. Vocabulary centers on denazification, demilitarisation, NATO expansion, Western interference, Russian world (Russky Mir), and historical Russian-Ukrainian unity. Coverage emphasises Russian military precision and humanitarian conduct, Ukrainian military targeting of civilians, and the illegitimacy of the post-Maidan Kyiv government. Prescription: complete the SMO''s territorial and political objectives; reject Western-imposed settlement frameworks; defend multipolar world order.', claim_de='Russische Staatsmedien und ausgerichtete Outlets rahmen den Krieg als defensive militaerische Spezialoperation (SMO) zum Schutz russischsprachiger Bevoelkerungen im Donbass und auf der Krim vor einem vom Westen eingesetzten Regime in Kiew, das seit 2014 ethnische Diskriminierung und NATO-Vormarsch betrieben habe. Das Vokabular kreist um Entnazifizierung, Entmilitarisierung, NATO-Erweiterung, westliche Einmischung, russische Welt (Russki Mir) und historische russisch-ukrainische Einheit. Berichterstattung betont russische militaerische Praezision und humanitaeres Verhalten, ukrainische militaerische Angriffe auf Zivilisten und Illegitimitaet der nach-Maidan-Regierung in Kiew. Vorschrift: territoriale und politische Ziele der SMO vollenden; westlich auferlegte Beilegungsrahmen ablehnen; multipolare Weltordnung verteidigen.', actor_centroids=ARRAY['EUROPE-RUSSIA','EUROPE-BELARUS'], framing_keywords=ARRAY['special military operation','SMO','denazification','demilitarisation','NATO expansion','Western interference','Russian world','Kyiv regime','Ukrainian Nazis','liberation of Donbas','Western proxy','multipolar order','defense of Russian-speakers','limited operation','targeted operation','restraint in scope','not full-scale','partial mobilisation','our people','brotherly people','fraternal nation'], publishers=ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV'], fn_id='ukraine_war_theater', display_order=2, stance_label_en='Special military operation framing', stance_label_de='Spezialoperation-Rahmung', stance= -2, framing_required=false, is_active=true WHERE id='russia_special_military_operation';
UPDATE narratives_v2 SET name_en='The war is a US/NATO proxy war prolonged by Western intervention; settlement requires restraint', name_de='Der Krieg ist ein US-/NATO-Stellvertreterkrieg, verlaengert durch westliche Intervention; Beilegung erfordert Zurueckhaltung', claim_en='Western contrarian, Global South, and some Chinese state media frame the war as a US/NATO proxy conflict that the West has prolonged through escalating weapons deliveries and refusal of early negotiation opportunities (notably the spring 2022 Istanbul talks). Vocabulary centers on proxy war, NATO expansion as root cause, blocked diplomacy, Western hubris, and Global Majority interests. Coverage emphasises the human and economic costs to Europe, the strain on Western unity, the unsustainability of the Ukrainian position over time, the legitimacy of Russian security concerns, and the absence of Global South support for the Western position. Prescription: immediate negotiated settlement, territorial realism, end weapons deliveries, recognise multipolar reality.', claim_de='Westliche Dissidenten-, Global-South- und einige chinesische Staatsmedien rahmen den Krieg als US-/NATO-Stellvertreterkonflikt, den der Westen durch eskalierende Waffenlieferungen und Ablehnung frueher Verhandlungschancen (insbesondere Istanbul-Gespraeche im Fruehjahr 2022) verlaengert habe. Das Vokabular kreist um Stellvertreterkrieg, NATO-Erweiterung als Grundursache, blockierte Diplomatie, westliche Hybris und Interessen der globalen Mehrheit. Berichterstattung betont menschliche und wirtschaftliche Kosten fuer Europa, Belastung westlicher Einheit, Unhaltbarkeit der ukrainischen Position auf Dauer, Legitimitaet russischer Sicherheitsbedenken und Abwesenheit von Global-South-Unterstuetzung fuer die westliche Position. Vorschrift: sofortige verhandelte Beilegung, territoriale Realitaet, Ende der Waffenlieferungen, multipolare Realitaet anerkennen.', actor_centroids=ARRAY['NON-STATE-EU','ASIA-CHINA','ASIA-INDIA'], framing_keywords=ARRAY['proxy war','NATO expansion','blocked diplomacy','negotiated settlement','territorial realism','Western escalation','Istanbul talks','Global South','multipolar order','Western hubris','strain on Europe'], publishers=ARRAY['Fox News','Global Times','CGTN','China Daily','Hindustan Times','Times of India','NDTV','The Hindu','WION','Dawn','Express Tribune','Al Jazeera','TRT World','Daily Sabah','Anadolu Agency','O Globo','Bangkok Post','News24','BRICS Info'], fn_id='ukraine_war_theater', display_order=3, stance_label_en='US/NATO proxy war critique', stance_label_de='Kritik am US-/NATO-Stellvertreterkrieg', stance= -1, framing_required=false, is_active=true WHERE id='proxy_war_restraint_critique';
UPDATE narratives_v2 SET name_en='Western military, economic, and industrial aid is sustaining and must be scaled', name_de='Westliche militaerische, wirtschaftliche und industrielle Hilfe traegt und muss skaliert werden', claim_en='Pro-aid framing (Ukrainian press + Western mainstream + Eastern European hawks) treats Western military, economic, and financial assistance as both moral imperative and strategic necessity. Coverage tracks weapons deliveries (HIMARS, ATACMS, Storm Shadow, Taurus debates, F-16 deployment, Patriot replenishment), financial mechanisms (ERA loan from windfall profits on frozen Russian assets, Ukraine Facility, REPO Act seizure provisions, European Peace Facility), and the growing defense-industrial partnership (Rheinmetall-Ukraine joint ventures, Czech ammunition initiative, BAE local production). Vocabulary: aid package, security assistance, defense industrial base, joint production, ammunition supply, frozen-asset windfall, sustained commitment. Prescription: scale all three channels; remove restrictions on Western weapons use; seize frozen sovereign assets for Ukrainian reconstruction; build long-term defense-industrial capacity in Ukraine.', claim_de='Pro-Hilfe-Rahmung (ukrainische Medien + westlicher Mainstream + osteuropaeische Falken) behandelt westliche militaerische, wirtschaftliche und finanzielle Unterstuetzung als moralische Pflicht und strategische Notwendigkeit. Berichterstattung verfolgt Waffenlieferungen (HIMARS, ATACMS, Storm Shadow, Taurus-Debatten, F-16-Stationierung, Patriot-Nachschub), Finanzmechanismen (ERA-Darlehen aus Sondervermoegens-Gewinnen eingefrorenen russischen Vermoegens, Ukraine-Fazilitaet, REPO-Act-Beschlagnahmebestimmungen, Europaeische Friedensfazilitaet) und die wachsende verteidigungsindustrielle Partnerschaft (Rheinmetall-Ukraine-Joint-Ventures, tschechische Munitions-Initiative, BAE-Lokalproduktion). Vokabular: Hilfspaket, Sicherheitsunterstuetzung, Verteidigungsindustrie-Basis, gemeinsame Produktion, Munitionsversorgung, Sondervermoegens-Windfall, anhaltendes Engagement. Vorschrift: alle drei Kanaele skalieren; Beschraenkungen westlichen Waffeneinsatzes aufheben; eingefrorenes Staatsvermoegen fuer ukrainischen Wiederaufbau beschlagnahmen; langfristige Verteidigungsindustrie-Kapazitaet in der Ukraine aufbauen.', actor_centroids=ARRAY['EUROPE-UKRAINE','EUROPE-UK','EUROPE-FRANCE','EUROPE-GERMANY','EUROPE-BALTIC','EUROPE-VISEGRAD','AMERICAS-USA'], framing_keywords=ARRAY['military aid','aid package','security assistance','weapons delivery','training mission','defence production','joint production','ammunition supply','frozen-asset windfall','ERA loan','seize frozen assets','sustained commitment','long-term partnership'], publishers=ARRAY['Kyiv Post','Reuters','Bloomberg','Financial Times','BBC World','The Guardian','The Telegraph','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Der Spiegel','Die Zeit','Tagesschau','Handelsblatt','Deutsche Welle','La Repubblica','ANSA','El País','ERR News','LRT English','LSM English','Atlantic Council','Associated Press','The Economist','EurActiv','Defense News','Janes','CNN','New York Times','Washington Post','Wall Street Journal','Politico','iROZHLAS'], fn_id='western_aid_to_ukraine', display_order=1, stance_label_en='Aid sustains Ukrainian defense', stance_label_de='Hilfe sichert ukrainische Verteidigung', stance=2, framing_required=false, is_active=true WHERE id='aid_sustains_defense';
UPDATE narratives_v2 SET name_en='Western aid prolongs proxy war, wastes taxpayer money, escalates direct NATO-Russia risk', name_de='Westliche Hilfe verlaengert Stellvertreterkrieg, verschwendet Steuergeld, eskaliert direktes NATO-Russland-Risiko', claim_en='Restraint framing (Russian state press + Western contrarian + Global South + Hungarian-aligned EU) treats Western aid as proxy-war escalation that delays inevitable settlement, wastes taxpayer money increasingly diverted from domestic priorities, and risks direct NATO-Russia confrontation by supplying longer-range weapons and authorising their use inside Russia. Vocabulary: proxy war, escalation, taxpayer waste, weapons graveyard, diversion of aid, NATO involvement, red line. Coverage emphasises the corruption risk in aid pipelines, the ineffectiveness of escalating weapons categories in changing the battlefield, Ukrainian losses and recruitment shortages, growing European public fatigue, and the strain on US bipartisan support. Prescription: pause and reassess aid, condition it on negotiated outcomes, prevent direct NATO-Russia escalation, redirect funds to domestic priorities.', claim_de='Zurueckhaltungs-Rahmung (russische Staatsmedien + westliche Dissidenten + Global South + ungarisch-orientierte EU) behandelt westliche Hilfe als Stellvertreterkriegs-Eskalation, die unvermeidliche Beilegung verzoegert, Steuergeld zunehmend von inlaendischen Prioritaeten umlenkt und direkte NATO-Russland-Konfrontation durch Lieferung weitreichenderer Waffen und deren Autorisierung in Russland riskiert. Vokabular: Stellvertreterkrieg, Eskalation, Steuerverschwendung, Waffenfriedhof, Umlenkung von Hilfe, NATO-Beteiligung, rote Linie. Berichterstattung betont Korruptionsrisiko in Hilfspipelines, Wirkungslosigkeit eskalierender Waffenkategorien fuer den Schlachtfeld-Wandel, ukrainische Verluste und Rekrutierungsmaengel, wachsende europaeische Erschoepfung der Oeffentlichkeit und Belastung ueberparteilicher US-Unterstuetzung. Vorschrift: Hilfe pausieren und neu bewerten, sie an verhandelten Ergebnissen konditionieren, direkte NATO-Russland-Eskalation verhindern, Mittel auf inlaendische Prioritaeten umleiten.', actor_centroids=ARRAY['EUROPE-RUSSIA','ASIA-CHINA','ASIA-INDIA'], framing_keywords=ARRAY['proxy war','escalation','taxpayer waste','weapons graveyard','aid diversion','NATO involvement','red line','red lines','corruption risk','aid fatigue','bipartisan strain','Western recklessness'], publishers=ARRAY['TASS','TASS (EN)','tass.com','RT','Lenta.ru','lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','RIA Novosti','BelTA','BelTA Russian','Press TV','Fox News','Global Times','CGTN','China Daily','Hindustan Times','Times of India','NDTV','TRT World','Daily Sabah'], fn_id='western_aid_to_ukraine', display_order=2, stance_label_en='Aid as escalation and proxy waste', stance_label_de='Hilfe als Eskalation und Stellvertreter-Verschwendung', stance= -2, framing_required=false, is_active=true WHERE id='aid_as_escalation_and_proxy';

COMMIT;
